mapper.select:
SELECT R.REPORT_ID, R.CLASS_ID, R.STUDENT_ID, S.STUDENT_NAME AS STUDENT_NAME, T.TEACHER_NAME AS TEACHER_NAME, R.REPORT_TYPE, R.PERIOD_TYPE, R.TITLE, TO_CHAR(R.START_DATE, 'YYYY-MM-DD') AS START_DATE, TO_CHAR(R.END_DATE, 'YYYY-MM-DD') AS END_DATE, TO_CHAR(R.CREATED_AT, 'YYYY-MM-DD HH24:MI') AS CREATED_AT, ( SELECT COUNT(*) FROM REPORT_VIEW RV WHERE RV.REPORT_ID = R.REPORT_ID AND RV.VIEWER_ID = #{parentId} ) AS PARENT_VIEW_COUNT, ( SELECT TO_CHAR(MAX(RV.VIEWER_AT), 'YYYY-MM-DD HH24:MI') FROM REPORT_VIEW RV WHERE RV.REPORT_ID = R.REPORT_ID AND RV.VIEWER_ID = #{parentId} ) AS PARENT_VIEWED_AT FROM REPORT R JOIN STUDENT_PARENT SP ON SP.STUDENT_ID = R.STUDENT_ID AND SP.PARENT_ID = #{parentId} AND NVL(SP.LINK_STATUS, 1) = 1 LEFT JOIN STUDENT S ON S.STUDENT_ID = R.STUDENT_ID LEFT JOIN TEACHER T ON T.TEACHER_ID = R.TEACHER_ID WHERE R.CLASS_ID = #{classId} AND R.REPORT_TYPE = 'PERSONAL'
AND R.STUDENT_ID = #{studentId}
ORDER BY R.START_DATE DESC, R.CREATED_AT DESC, R.REPORT_ID DESC

SELECT COUNT(*)
FROM REPORT_VIEW
WHERE REPORT_ID = #{reportId}
  AND VIEWER_ID = #{viewerId}

SELECT COUNT(*)
FROM TEACHER_CLASS TC
WHERE TC.TEACHER_ID = #{teacherId}
  AND TC.CLASS_ID = #{classId}
  AND TC.STATUS = 'ACTIVE'
  AND TC.END_DATE IS NULL

SELECT COUNT(*)
FROM STUDENT_CLASS SC
WHERE SC.STUDENT_ID = #{studentId}
  AND SC.CLASS_ID = #{classId}
  AND SC.END_DATE IS NULL

SELECT COUNT(*)
FROM STUDENT_PARENT SP
JOIN STUDENT_CLASS SC
  ON SC.STUDENT_ID = SP.STUDENT_ID
 AND SC.CLASS_ID = #{classId}
 AND SC.END_DATE IS NULL
WHERE SP.PARENT_ID = #{parentId}
  AND SP.STUDENT_ID = #{studentId}
  AND NVL(SP.LINK_STATUS, 1) = 1
